#include <stdio.h>
#include <math.h>
#define MOD 1000000007
long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}
long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, B, N;
        scanf("%lld %lld %lld", &A, &B, &N);
        long long val1 = (powmod(A, N) + powmod(B, N)) % MOD;
        long long val2 = abs(A - B);
        printf("%lld\n", gcd(val1, val2));
    }
    return 0;
}

