import java.util.Scanner;
public class Main {
    static final long MOD = 1000000007;
    public static long powmod(long a, long b) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }
    public static long gcd(long a, long b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long A = sc.nextLong();
            long B = sc.nextLong();
            long N = sc.nextLong();
            long val1 = (powmod(A, N) + powmod(B, N)) % MOD;
            long val2 = Math.abs(A - B);
            System.out.println(gcd(val1, val2));
        }
    }
}

