const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
function powmod(a, b) {
    let res = 1;
    while (b > 0) {
        if (b % 2 === 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b = Math.floor(b / 2);
    }
    return res;
}
function gcd(a, b) {
    if (b === 0) return a;
    return gcd(b, a % b);
}
const T = parseInt(input[idx++]);
for (let i = 0; i < T; i++) {
    const [A, B, N] = input[idx++].split(' ').map(Number);
    const val1 = (powmod(A, N) + powmod(B, N)) % MOD;
    const val2 = Math.abs(A - B);
    console.log(gcd(val1, val2));
}

